import os

def generate_lock_file(lock_file_path, package_manager):
    if package_manager == "pip":
        os.system(f"pip freeze > {lock_file_path}")
    elif package_manager == "poetry":
        os.system(f"poetry lock > {lock_file_path}")
    else:
        print("Unsupported package manager")

def update_lock_file(lock_file_path, package_manager):
    if package_manager == "pip":
        os.system(f"pip freeze > {lock_file_path}")
    elif package_manager == "poetry":
        os.system(f"poetry update")
    else:
        print("Unsupported package manager")

